// ─── Helpers ──────────────────────────────────────────────────────────────────
function initAttendance(students) {
  return students.reduce((acc, s) => ({ ...acc, [s.id]: {} }), {});
}

function getAttendanceStats(studentId, attendance) {
  const records = attendance[studentId] || {};
  const dates = Object.keys(records);
  if (!dates.length) return { pct: 0, present: 0, absent: 0, late: 0, total: 0 };
  const present = dates.filter(d => records[d] === "P").length;
  const absent = dates.filter(d => records[d] === "A").length;
  const late = dates.filter(d => records[d] === "T").length;
  return { pct: Math.round((present / dates.length) * 100), present, absent, late, total: dates.length };
}

