function Badge({ label, color, bg }) {
  return (
    <span style={{
      display: "inline-block", padding: "2px 10px", borderRadius: 999,
      fontSize: 11, fontWeight: 700, letterSpacing: ".05em",
      color, background: bg
    }}>{label}</span>
  );
}

function StatusBtn({ status, active, onClick, label }) {
  const map = {
    P: { bg: COLORS.emerald, label: "Presente" },
    A: { bg: COLORS.rose, label: "Ausente" },
    T: { bg: COLORS.amber, label: "Tardanza" },
    "": { bg: COLORS.gray200, label: "—" },
  };
  const cfg = map[status];
  return (
    <button onClick={onClick} title={cfg.label} style={{
      width: 34, height: 34, borderRadius: 8,
      border: active ? `2px solid ${COLORS.navy}` : "2px solid transparent",
      background: active ? cfg.bg : COLORS.gray100,
      color: active ? "#fff" : COLORS.gray400,
      fontWeight: 700, fontSize: 13, cursor: "pointer",
      transition: "all .15s", outline: "none",
      boxShadow: active ? "0 2px 8px rgba(0,0,0,.15)" : "none"
    }}>{status || "—"}</button>
  );
}

// ─── LOGIN ────────────────────────────────────────────────────────────────────
function Login({ users, onLogin }) {
  const [email, setEmail] = useState("");
  const [pass, setPass] = useState("");
  const [err, setErr] = useState("");

  function handleLogin() {
    const user = users.find(u => u.email === email && u.password === pass);
    if (!user) { setErr("Correo o contraseña incorrectos."); return; }
    setErr("");
    onLogin(user);
  }

  return (
    <div style={{
      minHeight: "100vh", background: `linear-gradient(135deg, ${COLORS.navy} 0%, ${COLORS.navyLight} 100%)`,
      display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Inter', system-ui, sans-serif"
    }}>
      <div style={{
        background: COLORS.white, borderRadius: 20, padding: "48px 40px",
        width: 380, boxShadow: "0 24px 64px rgba(0,0,0,.25)"
      }}>
        {/* Logo */}
        <div style={{ textAlign: "center", marginBottom: 28 }}>
          <img src={SCHOOL_LOGO} alt="Institución Educativa Simón Pezo Ismiño"
            style={{ width: 100, height: 100, objectFit: "contain", marginBottom: 12 }} />
          <h1 style={{ margin: 0, fontSize: 17, fontWeight: 800, color: COLORS.navy, lineHeight: 1.3 }}>
            I.E. Simón Pezo Ismiño
          </h1>
          <p style={{ margin: "4px 0 0", color: COLORS.gray400, fontSize: 12 }}>Sistema de Control de Asistencia</p>
        </div>

        {err && (
          <div style={{
            background: "#FFF1F2", border: `1px solid ${COLORS.rose}`,
            borderRadius: 8, padding: "10px 14px", marginBottom: 16,
            color: COLORS.rose, fontSize: 13
          }}>{err}</div>
        )}

        <label style={{ display: "block", marginBottom: 4, fontSize: 13, fontWeight: 600, color: COLORS.gray600 }}>
          Correo electrónico
        </label>
        <input value={email} onChange={e => setEmail(e.target.value)}
          placeholder="usuario@colegio.cl"
          style={inputStyle}
          onKeyDown={e => e.key === "Enter" && handleLogin()}
        />

        <label style={{ display: "block", marginBottom: 4, fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginTop: 16 }}>
          Contraseña
        </label>
        <input type="password" value={pass} onChange={e => setPass(e.target.value)}
          placeholder="••••••••"
          style={inputStyle}
          onKeyDown={e => e.key === "Enter" && handleLogin()}
        />

        <button onClick={handleLogin} style={{
          width: "100%", marginTop: 24, padding: "12px",
          background: `linear-gradient(135deg, ${COLORS.navy}, ${COLORS.navyLight})`,
          color: "#fff", border: "none", borderRadius: 10,
          fontSize: 15, fontWeight: 700, cursor: "pointer",
          boxShadow: "0 4px 16px rgba(27,42,74,.35)", letterSpacing: ".03em"
        }}>Iniciar sesión</button>

        <p style={{ textAlign: "center", marginTop: 20, fontSize: 12, color: COLORS.gray400 }}>
          Admin: admin@colegio.pe / admin123
        </p>
      </div>
    </div>
  );
}

