// ─── ATTENDANCE VIEW ───────────────────────────────────────────────────────────
function AttendanceView({ user, students, attendance, setAttendance }) {
  const classes = user.classes || [];
  const [selectedClass, setSelectedClass] = useState(classes[0] || "");
  const [date, setDate] = useState(TODAY);
  const [saved, setSaved] = useState(false);

  const classStudents = students.filter(s => s.course === selectedClass);

  function mark(studentId, status) {
    setAttendance(prev => ({
      ...prev,
      [studentId]: { ...(prev[studentId] || {}), [date]: status }
    }));
    setSaved(false);
  }

  function saveAll() { setSaved(true); setTimeout(() => setSaved(false), 2500); }

  function markAll(status) {
    setAttendance(prev => {
      const updated = { ...prev };
      classStudents.forEach(s => {
        updated[s.id] = { ...(updated[s.id] || {}), [date]: status };
      });
      return updated;
    });
    setSaved(false);
  }

  const statusCount = { P: 0, A: 0, T: 0 };
  classStudents.forEach(s => {
    const v = (attendance[s.id] || {})[date];
    if (v) statusCount[v]++;
  });

  return (
    <div>
      <h2 style={pageTitle}>Tomar Asistencia</h2>

      {/* Controls */}
      <div style={{ display: "flex", gap: 12, marginBottom: 20, flexWrap: "wrap", alignItems: "center" }}>
        <select value={selectedClass} onChange={e => setSelectedClass(e.target.value)} style={selectStyle}>
          {classes.map(c => <option key={c}>{c}</option>)}
        </select>
        <input type="date" value={date} onChange={e => setDate(e.target.value)} style={selectStyle} />
        <button onClick={() => markAll("P")} style={actionBtn(COLORS.emerald)}>✅ Todos Presentes</button>
        <button onClick={() => markAll("A")} style={actionBtn(COLORS.rose)}>❌ Todos Ausentes</button>
      </div>

      {/* Summary pills */}
      <div style={{ display: "flex", gap: 12, marginBottom: 20 }}>
        {[
          { label: "Presentes", val: statusCount.P, color: COLORS.emerald, bg: "#D1FAE5" },
          { label: "Ausentes", val: statusCount.A, color: COLORS.rose, bg: "#FFE4E6" },
          { label: "Tardanzas", val: statusCount.T, color: COLORS.amber, bg: "#FEF3C7" },
          { label: "Sin marcar", val: classStudents.length - statusCount.P - statusCount.A - statusCount.T, color: COLORS.gray600, bg: COLORS.gray100 },
        ].map(p => (
          <div key={p.label} style={{
            padding: "8px 16px", borderRadius: 10, background: p.bg,
            color: p.color, fontWeight: 700, fontSize: 13
          }}>{p.val} {p.label}</div>
        ))}
      </div>

      {/* Table */}
      <div style={card}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: COLORS.gray50 }}>
              {["#", "Nombre", "RUT/ID", "Estado"].map(h => (
                <th key={h} style={th}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {classStudents.map((s, i) => {
              const current = (attendance[s.id] || {})[date] || "";
              return (
                <tr key={s.id} style={{ borderBottom: `1px solid ${COLORS.gray100}` }}>
                  <td style={td}><span style={{ color: COLORS.gray400, fontSize: 12, fontFamily: "monospace" }}>{String(i + 1).padStart(2, "0")}</span></td>
                  <td style={td}><span style={{ fontWeight: 600, color: COLORS.gray800 }}>{s.name}</span></td>
                  <td style={{ ...td, fontFamily: "monospace", fontSize: 13, color: COLORS.gray600 }}>{s.rut}</td>
                  <td style={td}>
                    <div style={{ display: "flex", gap: 6 }}>
                      {["P", "A", "T"].map(st => (
                        <StatusBtn key={st} status={st} active={current === st}
                          onClick={() => mark(s.id, current === st ? "" : st)} />
                      ))}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {classStudents.length === 0 && (
          <p style={{ textAlign: "center", color: COLORS.gray400, padding: 32 }}>
            No hay estudiantes en este curso.
          </p>
        )}
      </div>

      <div style={{ marginTop: 16, display: "flex", gap: 12, alignItems: "center" }}>
        <button onClick={saveAll} style={{
          padding: "12px 28px", background: COLORS.navy, color: "#fff",
          border: "none", borderRadius: 10, fontWeight: 700, fontSize: 14, cursor: "pointer"
        }}>💾 Guardar Asistencia</button>
        {saved && <span style={{ color: COLORS.emerald, fontWeight: 600 }}>✓ Guardado correctamente</span>}
      </div>
    </div>
  );
}

// ─── MONTHLY CALENDAR COMPONENT ──────────────────────────────────────────────
function MonthCalendar({ year, month, records }) {
  const DAYS = ["Dom", "Lun", "Mar", "Mié", "Jue", "Vie", "Sáb"];
  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const cells = [];
  for (let i = 0; i < firstDay; i++) cells.push(null);
  for (let d = 1; d <= daysInMonth; d++) cells.push(d);

  const monthNames = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];

  return (
    <div style={{ background: COLORS.white, borderRadius: 12, border: `1px solid ${COLORS.gray100}`, overflow: "hidden", minWidth: 240 }}>
      {/* Month header */}
      <div style={{
        background: `linear-gradient(135deg, ${COLORS.navy}, ${COLORS.navyLight})`,
        padding: "10px 14px", textAlign: "center",
        color: "#fff", fontWeight: 700, fontSize: 13
      }}>{monthNames[month]} {year}</div>

      {/* Day names */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 2, padding: "8px 8px 4px" }}>
        {DAYS.map(d => (
          <div key={d} style={{ textAlign: "center", fontSize: 10, fontWeight: 700, color: COLORS.gray400, letterSpacing: ".04em" }}>{d}</div>
        ))}
      </div>

      {/* Day cells */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 3, padding: "0 8px 10px" }}>
        {cells.map((day, i) => {
          if (!day) return <div key={`empty-${i}`} />;
          const dateStr = `${year}-${String(month + 1).padStart(2,"0")}-${String(day).padStart(2,"0")}`;
          const v = records[dateStr];
          const bgMap = { P: COLORS.emerald, A: COLORS.rose, T: COLORS.amber };
          const bg = bgMap[v] || COLORS.gray100;
          const textColor = v ? "#fff" : COLORS.gray400;
          const isWeekend = [0, 6].includes(new Date(year, month, day).getDay());
          return (
            <div key={day} title={v ? `${dateStr}: ${v === "P" ? "Presente" : v === "A" ? "Ausente" : "Tardanza"}` : dateStr}
              style={{
                height: 30, borderRadius: 6, display: "flex", flexDirection: "column",
                alignItems: "center", justifyContent: "center",
                background: v ? bg : isWeekend ? "transparent" : COLORS.gray50,
                border: v ? "none" : `1px solid ${isWeekend ? "transparent" : COLORS.gray100}`,
                cursor: v ? "default" : "default",
              }}>
              <span style={{ fontSize: 11, fontWeight: v ? 700 : 500, color: isWeekend && !v ? COLORS.gray300 : textColor, lineHeight: 1 }}>{day}</span>
              {v && <span style={{ fontSize: 8, color: "rgba(255,255,255,.8)", fontWeight: 700, lineHeight: 1 }}>{v}</span>}
            </div>
          );
        })}
      </div>

      {/* Month stats */}
      {(() => {
        const vals = Object.entries(records)
          .filter(([d]) => {
            const dm = new Date(d);
            return dm.getFullYear() === year && dm.getMonth() === month;
          })
          .map(([, v]) => v);
        const p = vals.filter(v => v === "P").length;
        const a = vals.filter(v => v === "A").length;
        const t = vals.filter(v => v === "T").length;
        if (!vals.length) return <div style={{ padding: "0 10px 10px", textAlign: "center", fontSize: 11, color: COLORS.gray300 }}>Sin registros</div>;
        const pct = Math.round((p / vals.length) * 100);
        return (
          <div style={{ padding: "0 10px 10px", display: "flex", justifyContent: "space-around", borderTop: `1px solid ${COLORS.gray100}`, paddingTop: 8 }}>
            <span style={{ fontSize: 11, color: COLORS.emerald, fontWeight: 700 }}>✓ {p}</span>
            <span style={{ fontSize: 11, color: COLORS.rose, fontWeight: 700 }}>✗ {a}</span>
            <span style={{ fontSize: 11, color: COLORS.amber, fontWeight: 700 }}>T {t}</span>
            <span style={{ fontSize: 11, color: pct >= 75 ? COLORS.emerald : pct >= 50 ? COLORS.amber : COLORS.rose, fontWeight: 700 }}>{pct}%</span>
          </div>
        );
      })()}
    </div>
  );
}

// ─── STUDENT DETAIL MODAL ─────────────────────────────────────────────────────
function StudentDetailModal({ student, attendance, onClose }) {
  const records = attendance[student.id] || {};
  const allDates = Object.keys(records).sort();

  // Get all months that have data
  const months = [...new Set(allDates.map(d => d.slice(0, 7)))].sort();
  const monthsWithData = months.map(m => {
    const [y, mo] = m.split("-").map(Number);
    return { year: y, month: mo - 1 };
  });

  // If no data, show current month
  const now = new Date();
  const displayMonths = monthsWithData.length > 0 ? monthsWithData : [{ year: now.getFullYear(), month: now.getMonth() }];

  const stats = getAttendanceStats(student.id, attendance);
  const pctColor = stats.pct >= 75 ? COLORS.emerald : stats.pct >= 50 ? COLORS.amber : COLORS.rose;

  return (
    <div style={{ ...modalOverlay, alignItems: "flex-start", paddingTop: 40, overflowY: "auto" }}>
      <div style={{ background: COLORS.white, borderRadius: 20, width: "min(92vw, 860px)", boxShadow: "0 24px 64px rgba(0,0,0,.25)", margin: "0 auto 40px" }}>
        {/* Header */}
        <div style={{
          background: `linear-gradient(135deg, ${COLORS.navy}, ${COLORS.navyLight})`,
          borderRadius: "20px 20px 0 0", padding: "24px 28px",
          display: "flex", justifyContent: "space-between", alignItems: "flex-start"
        }}>
          <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
            <div style={{
              width: 52, height: 52, borderRadius: "50%",
              background: `linear-gradient(135deg, ${COLORS.sky}, ${COLORS.emerald})`,
              display: "flex", alignItems: "center", justifyContent: "center",
              color: "#fff", fontWeight: 800, fontSize: 20
            }}>{student.name[0]}</div>
            <div>
              <div style={{ color: "#fff", fontWeight: 800, fontSize: 18 }}>{student.name}</div>
              <div style={{ color: "rgba(255,255,255,.6)", fontSize: 13, marginTop: 2 }}>
                {student.rut} · Curso {student.course}
              </div>
            </div>
          </div>
          <button onClick={onClose} style={{
            background: "rgba(255,255,255,.15)", border: "none", color: "#fff",
            width: 34, height: 34, borderRadius: 8, cursor: "pointer", fontSize: 16,
            display: "flex", alignItems: "center", justifyContent: "center"
          }}>✕</button>
        </div>

        <div style={{ padding: "24px 28px" }}>
          {/* Global stats */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12, marginBottom: 24 }}>
            {[
              { label: "Presentes", val: stats.present, color: COLORS.emerald, bg: "#D1FAE5" },
              { label: "Ausentes", val: stats.absent, color: COLORS.rose, bg: "#FFE4E6" },
              { label: "Tardanzas", val: stats.late, color: COLORS.amber, bg: "#FEF3C7" },
              { label: "% Asistencia", val: `${stats.pct}%`, color: pctColor, bg: pctColor + "22" },
            ].map(s => (
              <div key={s.label} style={{ background: s.bg, borderRadius: 12, padding: "14px", textAlign: "center" }}>
                <div style={{ fontSize: 22, fontWeight: 800, color: s.color }}>{s.val}</div>
                <div style={{ fontSize: 11, color: s.color, fontWeight: 600, marginTop: 2 }}>{s.label}</div>
              </div>
            ))}
          </div>

          {/* Legend */}
          <div style={{ display: "flex", gap: 16, marginBottom: 20, flexWrap: "wrap" }}>
            {[
              { color: COLORS.emerald, label: "Presente (P)" },
              { color: COLORS.rose, label: "Ausente (A)" },
              { color: COLORS.amber, label: "Tardanza (T)" },
              { color: COLORS.gray100, label: "Sin clase", text: COLORS.gray400 },
            ].map(l => (
              <div key={l.label} style={{ display: "flex", alignItems: "center", gap: 6 }}>
                <div style={{ width: 14, height: 14, borderRadius: 4, background: l.color }} />
                <span style={{ fontSize: 12, color: COLORS.gray600 }}>{l.label}</span>
              </div>
            ))}
          </div>

          {/* Calendar grid */}
          <h3 style={{ margin: "0 0 16px", color: COLORS.navy, fontWeight: 700, fontSize: 15 }}>
            📅 Historial mensual
          </h3>
          {displayMonths.length === 0 ? (
            <div style={{ textAlign: "center", padding: 32, color: COLORS.gray400 }}>
              No hay registros de asistencia aún.
            </div>
          ) : (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(240px,1fr))", gap: 16 }}>
              {displayMonths.map(({ year, month }) => (
                <MonthCalendar key={`${year}-${month}`} year={year} month={month} records={records} />
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── REPORTS VIEW ─────────────────────────────────────────────────────────────
function ReportsView({ user, students, attendance }) {
  const availableClasses = user.role === "admin"
    ? [...new Set(students.map(s => s.course))]
    : (user.classes || []);
  const [selectedClass, setSelectedClass] = useState(availableClasses[0] || "");
  const [selectedStudent, setSelectedStudent] = useState(null);

  const classStudents = students.filter(s => s.course === selectedClass);

  function exportExcel() {
    const rows = classStudents.map(s => {
      const stats = getAttendanceStats(s.id, attendance);
      const records = attendance[s.id] || {};
      return {
        Nombre: s.name,
        "RUT/ID": s.rut,
        Curso: s.course,
        "% Asistencia": `${stats.pct}%`,
        Presentes: stats.present,
        Ausentes: stats.absent,
        Tardanzas: stats.late,
        "Total Clases": stats.total,
        ...Object.fromEntries(Object.entries(records).sort()),
      };
    });
    const ws = XLSX.utils.json_to_sheet(rows);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, `Asistencia ${selectedClass}`);
    XLSX.writeFile(wb, `Asistencia_${selectedClass}_${TODAY}.xlsx`);
  }

  const allDates = [...new Set(
    classStudents.flatMap(s => Object.keys(attendance[s.id] || {}))
  )].sort();

  return (
    <div>
      {selectedStudent && (
        <StudentDetailModal
          student={selectedStudent}
          attendance={attendance}
          onClose={() => setSelectedStudent(null)}
        />
      )}

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24 }}>
        <h2 style={{ ...pageTitle, margin: 0 }}>Reportes de Asistencia</h2>
        <button onClick={exportExcel} style={{
          padding: "10px 20px", background: COLORS.emerald, color: "#fff",
          border: "none", borderRadius: 10, fontWeight: 700, fontSize: 13,
          cursor: "pointer", display: "flex", alignItems: "center", gap: 8
        }}>📥 Exportar Excel</button>
      </div>

      <select value={selectedClass} onChange={e => setSelectedClass(e.target.value)} style={{ ...selectStyle, marginBottom: 20 }}>
        {availableClasses.map(c => <option key={c}>{c}</option>)}
      </select>

      {/* Stats cards */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(150px,1fr))", gap: 16, marginBottom: 24 }}>
        {[
          { label: "Total alumnos", val: classStudents.length, icon: "🎓", color: COLORS.navy },
          {
            label: "Asist. promedio", icon: "📈", color: COLORS.emerald,
            val: classStudents.length
              ? Math.round(classStudents.reduce((a, s) => a + getAttendanceStats(s.id, attendance).pct, 0) / classStudents.length) + "%"
              : "—"
          },
          { label: "Clases registradas", val: allDates.length, icon: "📅", color: COLORS.sky },
        ].map(c => (
          <div key={c.label} style={{ ...card, padding: "20px", textAlign: "center" }}>
            <div style={{ fontSize: 28 }}>{c.icon}</div>
            <div style={{ fontSize: 26, fontWeight: 800, color: c.color, marginTop: 4 }}>{c.val}</div>
            <div style={{ fontSize: 12, color: COLORS.gray400, marginTop: 2 }}>{c.label}</div>
          </div>
        ))}
      </div>

      {/* Per-student summary — click to open calendar */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
        <h3 style={{ margin: 0, color: COLORS.navy, fontWeight: 700 }}>Resumen por estudiante</h3>
        <span style={{ fontSize: 12, color: COLORS.gray400 }}>Haz clic en un alumno para ver su calendario mensual 📅</span>
      </div>
      <div style={card}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: COLORS.gray50 }}>
              {["Nombre", "RUT/ID", "Presentes", "Ausentes", "Tardanzas", "% Asistencia", ""].map(h => (
                <th key={h} style={th}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {classStudents.map(s => {
              const stats = getAttendanceStats(s.id, attendance);
              const pctColor = stats.pct >= 75 ? COLORS.emerald : stats.pct >= 50 ? COLORS.amber : COLORS.rose;
              return (
                <tr key={s.id} style={{ borderBottom: `1px solid ${COLORS.gray100}`, cursor: "pointer" }}
                  onClick={() => setSelectedStudent(s)}
                  onMouseEnter={e => e.currentTarget.style.background = COLORS.gray50}
                  onMouseLeave={e => e.currentTarget.style.background = "transparent"}
                >
                  <td style={{ ...td, fontWeight: 600 }}>{s.name}</td>
                  <td style={{ ...td, fontFamily: "monospace", fontSize: 13, color: COLORS.gray600 }}>{s.rut}</td>
                  <td style={{ ...td, color: COLORS.emerald, fontWeight: 700 }}>{stats.present}</td>
                  <td style={{ ...td, color: COLORS.rose, fontWeight: 700 }}>{stats.absent}</td>
                  <td style={{ ...td, color: COLORS.amber, fontWeight: 700 }}>{stats.late}</td>
                  <td style={td}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <div style={{ height: 6, flex: 1, borderRadius: 99, background: COLORS.gray100, overflow: "hidden" }}>
                        <div style={{ height: "100%", borderRadius: 99, width: `${stats.pct}%`, background: pctColor }} />
                      </div>
                      <span style={{ fontWeight: 700, fontSize: 13, color: pctColor, minWidth: 36 }}>{stats.pct}%</span>
                    </div>
                  </td>
                  <td style={td}>
                    <span style={{
                      fontSize: 11, fontWeight: 600, color: COLORS.sky,
                      background: COLORS.sky + "22", padding: "4px 10px", borderRadius: 6,
                      whiteSpace: "nowrap"
                    }}>Ver calendario →</span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {classStudents.length === 0 && (
          <p style={{ textAlign: "center", color: COLORS.gray400, padding: 32 }}>Sin estudiantes en este curso.</p>
        )}
      </div>
    </div>
  );
}

// ─── ADMIN: TEACHERS ──────────────────────────────────────────────────────────
function TeachersView({ users, setUsers, students, classrooms }) {
  const teachers = users.filter(u => u.role === "teacher");
  // Combina aulas registradas + cursos de estudiantes para no perder ninguna
  const allCourses = [...new Set([
    ...classrooms.map(c => c.name),
    ...students.map(s => s.course)
  ])].sort();
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ name: "", email: "", password: "", classes: [] });
  const [editId, setEditId] = useState(null);

  function save() {
    if (!form.name || !form.email || !form.password) return;
    if (editId) {
      setUsers(prev => prev.map(u => u.id === editId ? { ...u, ...form } : u));
      setEditId(null);
    } else {
      setUsers(prev => [...prev, { ...form, id: `t${Date.now()}`, role: "teacher" }]);
    }
    setForm({ name: "", email: "", password: "", classes: [] });
    setShowModal(false);
  }

  function del(id) {
    if (window.confirm("¿Eliminar este docente?")) {
      setUsers(prev => prev.filter(u => u.id !== id));
    }
  }

  function openEdit(t) {
    setForm({ name: t.name, email: t.email, password: t.password, classes: t.classes || [] });
    setEditId(t.id);
    setShowModal(true);
  }

  function toggleCourse(c) {
    setForm(f => ({
      ...f,
      classes: f.classes.includes(c) ? f.classes.filter(x => x !== c) : [...f.classes, c]
    }));
  }

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24 }}>
        <h2 style={{ ...pageTitle, margin: 0 }}>Gestión de Docentes</h2>
        <button onClick={() => { setShowModal(true); setEditId(null); setForm({ name: "", email: "", password: "", classes: [] }); }}
          style={{ padding: "10px 20px", background: COLORS.navy, color: "#fff", border: "none", borderRadius: 10, fontWeight: 700, fontSize: 13, cursor: "pointer" }}>
          + Agregar Docente
        </button>
      </div>

      <div style={{ display: "grid", gap: 16 }}>
        {teachers.map(t => (
          <div key={t.id} style={{ ...card, display: "flex", justifyContent: "space-between", alignItems: "center", padding: "16px 20px" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
              <div style={{
                width: 44, height: 44, borderRadius: "50%",
                background: `linear-gradient(135deg, ${COLORS.navy}, ${COLORS.sky})`,
                display: "flex", alignItems: "center", justifyContent: "center",
                color: "#fff", fontWeight: 700, fontSize: 16
              }}>{t.name[0]}</div>
              <div>
                <div style={{ fontWeight: 700, color: COLORS.gray800 }}>{t.name}</div>
                <div style={{ fontSize: 13, color: COLORS.gray400 }}>{t.email}</div>
                <div style={{ marginTop: 4, display: "flex", gap: 6, flexWrap: "wrap" }}>
                  {(t.classes || []).map(c => (
                    <Badge key={c} label={`Curso ${c}`} color={COLORS.navy} bg={COLORS.sky + "33"} />
                  ))}
                </div>
              </div>
            </div>
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={() => openEdit(t)} style={iconBtn("#EFF6FF", COLORS.sky)}>✏️</button>
              <button onClick={() => del(t.id)} style={iconBtn("#FFF1F2", COLORS.rose)}>🗑️</button>
            </div>
          </div>
        ))}
      </div>

      {showModal && (
        <div style={modalOverlay}>
          <div style={modalBox}>
            <h3 style={{ margin: "0 0 20px", color: COLORS.navy }}>{editId ? "Editar Docente" : "Nuevo Docente"}</h3>
            {[
              { label: "Nombre completo", key: "name", type: "text" },
              { label: "Correo electrónico", key: "email", type: "email" },
              { label: "Contraseña", key: "password", type: "password" },
            ].map(f => (
              <div key={f.key} style={{ marginBottom: 14 }}>
                <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginBottom: 4 }}>{f.label}</label>
                <input type={f.type} value={form[f.key]} onChange={e => setForm(p => ({ ...p, [f.key]: e.target.value }))}
                  style={inputStyle} />
              </div>
            ))}
            <div style={{ marginBottom: 20 }}>
              <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginBottom: 4 }}>
                Aulas asignadas
                {form.classes.length > 0 && (
                  <span style={{ marginLeft: 8, background: COLORS.sky, color: "#fff", borderRadius: 99, padding: "1px 8px", fontSize: 11, fontWeight: 700 }}>
                    {form.classes.length} seleccionada(s)
                  </span>
                )}
              </label>
              <p style={{ margin: "0 0 8px", fontSize: 12, color: COLORS.gray400 }}>Toca las aulas para asignar o quitar acceso al docente</p>
              {allCourses.length === 0 ? (
                <div style={{ background: "#FFF7ED", border: `1px solid ${COLORS.amber}44`, borderRadius: 8, padding: "10px 14px", fontSize: 13, color: COLORS.amber }}>
                  ⚠️ No hay aulas creadas. Ve a <strong>Aulas</strong> para crear una primero.
                </div>
              ) : (
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                  {allCourses.map(c => {
                    const selected = form.classes.includes(c);
                    return (
                      <button key={c} onClick={() => toggleCourse(c)} style={{
                        padding: "8px 16px", borderRadius: 8, cursor: "pointer", fontWeight: 700, fontSize: 13,
                        border: `2px solid ${selected ? COLORS.navy : COLORS.gray200}`,
                        background: selected ? COLORS.navy : COLORS.white,
                        color: selected ? "#fff" : COLORS.gray600,
                        transition: "all .15s",
                        display: "flex", alignItems: "center", gap: 6
                      }}>
                        {selected ? "✓ " : ""}{c}
                      </button>
                    );
                  })}
                </div>
              )}
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={save} style={{ flex: 1, padding: "11px", background: COLORS.navy, color: "#fff", border: "none", borderRadius: 10, fontWeight: 700, cursor: "pointer" }}>
                {editId ? "Guardar cambios" : "Crear docente"}
              </button>
              <button onClick={() => setShowModal(false)} style={{ padding: "11px 20px", background: COLORS.gray100, color: COLORS.gray600, border: "none", borderRadius: 10, fontWeight: 600, cursor: "pointer" }}>
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── ADMIN: STUDENTS ──────────────────────────────────────────────────────────
function StudentsView({ students, setStudents }) {
  const fileRef = useRef();
  const [filterCourse, setFilterCourse] = useState("Todos");
  const allCourses = ["Todos", ...new Set(students.map(s => s.course))];
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ name: "", rut: "", course: "" });
  const [importStatus, setImportStatus] = useState(null); // null | "loading" | "ok" | "error"
  const [importMsg, setImportMsg] = useState("");

  function importExcel(e) {
    const file = e.target.files[0];
    if (!file) return;
    setImportStatus("loading");
    setImportMsg("Leyendo archivo...");

    const reader = new FileReader();
    reader.onerror = () => {
      setImportStatus("error");
      setImportMsg("No se pudo leer el archivo. Intenta de nuevo.");
    };
    reader.onload = ev => {
      try {
        const data = new Uint8Array(ev.target.result);
        const wb = XLSX.read(data, { type: "array" });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const rows = XLSX.utils.sheet_to_json(ws, { defval: "" });

        // Flexible column matching (handles spaces and case variations)
        const normalize = s => String(s).trim().toLowerCase();
        const findKey = (row, candidates) =>
          Object.keys(row).find(k => candidates.includes(normalize(k)));

        const newStudents = rows
          .map((r, i) => {
            const kName = findKey(r, ["nombre", "name", "alumno", "estudiante"]);
            const kRut  = findKey(r, ["rut/id", "rut", "id", "dni", "codigo"]);
            const kCourse = findKey(r, ["curso", "aula", "grado", "clase", "section"]);
            if (!kName || !kRut || !kCourse) return null;
            const name = String(r[kName]).trim();
            const rut  = String(r[kRut]).trim();
            const course = String(r[kCourse]).trim();
            if (!name || !rut || !course) return null;
            return { id: `imp_${Date.now()}_${i}`, name, rut, course };
          })
          .filter(Boolean);

        if (newStudents.length === 0) {
          setImportStatus("error");
          setImportMsg("No se encontraron estudiantes. Verifica que el archivo tenga columnas: Nombre, RUT/ID, Curso");
          e.target.value = "";
          return;
        }

        setStudents(prev => {
          const existing = new Set(prev.map(s => s.rut));
          const added = newStudents.filter(s => !existing.has(s.rut));
          setImportStatus("ok");
          setImportMsg(`✅ ${added.length} estudiante(s) importado(s) correctamente.${newStudents.length - added.length > 0 ? ` (${newStudents.length - added.length} ya existían)` : ""}`);
          return [...prev, ...added];
        });
      } catch (err) {
        setImportStatus("error");
        setImportMsg("Error al procesar el archivo. Asegúrate de que sea un .xlsx válido.");
      }
      e.target.value = "";
    };
    reader.readAsArrayBuffer(file);
  }

  function downloadTemplate() {
    const ws = XLSX.utils.json_to_sheet([
      { Nombre: "Juan Pérez", "RUT/ID": "11.111.111-1", Curso: "1A" },
      { Nombre: "María López", "RUT/ID": "22.222.222-2", Curso: "2B" },
      { Nombre: "Carlos Ruiz", "RUT/ID": "33.333.333-3", Curso: "3A" },
    ]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Estudiantes");
    XLSX.writeFile(wb, "plantilla_estudiantes.xlsx");
  }

  function addStudent() {
    if (!form.name || !form.rut || !form.course) return;
    setStudents(prev => [...prev, { ...form, id: `s${Date.now()}` }]);
    setForm({ name: "", rut: "", course: "" });
    setShowModal(false);
  }

  function del(id) {
    if (window.confirm("¿Eliminar este estudiante?")) {
      setStudents(prev => prev.filter(s => s.id !== id));
    }
  }

  const filtered = filterCourse === "Todos" ? students : students.filter(s => s.course === filterCourse);

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16, flexWrap: "wrap", gap: 10 }}>
        <h2 style={{ ...pageTitle, margin: 0 }}>Gestión de Estudiantes</h2>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
          <button onClick={downloadTemplate} style={{ ...actionBtn(COLORS.amber), fontSize: 12 }}>📄 Plantilla</button>
          <button onClick={() => fileRef.current.click()} style={{ ...actionBtn(COLORS.sky), fontSize: 12 }}>📤 Importar Excel</button>
          <button onClick={() => setShowModal(true)} style={{ padding: "9px 16px", background: COLORS.navy, color: "#fff", border: "none", borderRadius: 10, fontWeight: 700, fontSize: 13, cursor: "pointer" }}>
            + Agregar
          </button>
        </div>
      </div>

      {/* Import status banner */}
      {importStatus && (
        <div style={{
          padding: "12px 16px", borderRadius: 10, marginBottom: 16, fontSize: 13, fontWeight: 600,
          background: importStatus === "ok" ? "#D1FAE5" : importStatus === "error" ? "#FFE4E6" : "#EFF6FF",
          color: importStatus === "ok" ? COLORS.emerald : importStatus === "error" ? COLORS.rose : COLORS.sky,
          border: `1px solid ${importStatus === "ok" ? COLORS.emerald : importStatus === "error" ? COLORS.rose : COLORS.sky}44`,
          display: "flex", justifyContent: "space-between", alignItems: "center"
        }}>
          <span>{importStatus === "loading" ? "⏳ " : ""}{importMsg}</span>
          <button onClick={() => setImportStatus(null)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 16, color: "inherit" }}>✕</button>
        </div>
      )}

      {/* Instrucciones de importación */}
      <div style={{ background: "#EFF6FF", border: `1px solid ${COLORS.sky}44`, borderRadius: 10, padding: "10px 14px", marginBottom: 16, fontSize: 12, color: COLORS.navy }}>
        💡 <strong>Para importar:</strong> El archivo Excel debe tener columnas <strong>Nombre</strong>, <strong>RUT/ID</strong> y <strong>Curso</strong>. Descarga la plantilla si no tienes una.
      </div>

      <input ref={fileRef} type="file" accept=".xlsx,.xls,.csv" style={{ display: "none" }} onChange={importExcel} />

      <div style={{ marginBottom: 16, display: "flex", gap: 8, flexWrap: "wrap" }}>
        {allCourses.map(c => (
          <button key={c} onClick={() => setFilterCourse(c)} style={{
            padding: "6px 16px", borderRadius: 20, border: "none", cursor: "pointer", fontWeight: 600, fontSize: 13,
            background: filterCourse === c ? COLORS.navy : COLORS.gray100,
            color: filterCourse === c ? "#fff" : COLORS.gray600,
          }}>{c}</button>
        ))}
      </div>

      <div style={card}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: COLORS.gray50 }}>
              {["#", "Nombre", "RUT/ID", "Curso", ""].map(h => <th key={h} style={th}>{h}</th>)}
            </tr>
          </thead>
          <tbody>
            {filtered.map((s, i) => (
              <tr key={s.id} style={{ borderBottom: `1px solid ${COLORS.gray100}` }}>
                <td style={td}><span style={{ color: COLORS.gray400, fontSize: 12, fontFamily: "monospace" }}>{String(i + 1).padStart(2, "0")}</span></td>
                <td style={{ ...td, fontWeight: 600 }}>{s.name}</td>
                <td style={{ ...td, fontFamily: "monospace", fontSize: 13, color: COLORS.gray600 }}>{s.rut}</td>
                <td style={td}><Badge label={`Curso ${s.course}`} color={COLORS.navy} bg={COLORS.sky + "33"} /></td>
                <td style={td}>
                  <button onClick={() => del(s.id)} style={iconBtn("#FFF1F2", COLORS.rose)}>🗑️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filtered.length === 0 && (
          <p style={{ textAlign: "center", color: COLORS.gray400, padding: 32 }}>
            No hay estudiantes. Importa desde Excel o agrega manualmente.
          </p>
        )}
      </div>

      {showModal && (
        <div style={modalOverlay}>
          <div style={modalBox}>
            <h3 style={{ margin: "0 0 20px", color: COLORS.navy }}>Nuevo Estudiante</h3>
            {[
              { label: "Nombre completo", key: "name" },
              { label: "RUT / ID", key: "rut" },
              { label: "Curso (ej: 1A)", key: "course" },
            ].map(f => (
              <div key={f.key} style={{ marginBottom: 14 }}>
                <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginBottom: 4 }}>{f.label}</label>
                <input value={form[f.key]} onChange={e => setForm(p => ({ ...p, [f.key]: e.target.value }))} style={inputStyle} />
              </div>
            ))}
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={addStudent} style={{ flex: 1, padding: "11px", background: COLORS.navy, color: "#fff", border: "none", borderRadius: 10, fontWeight: 700, cursor: "pointer" }}>
                Agregar
              </button>
              <button onClick={() => setShowModal(false)} style={{ padding: "11px 20px", background: COLORS.gray100, color: COLORS.gray600, border: "none", borderRadius: 10, fontWeight: 600, cursor: "pointer" }}>
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── ADMIN: CLASSROOMS ───────────────────────────────────────────────────────
const INITIAL_CLASSROOMS = [
  { id: "c1", name: "1A", grade: "1°", section: "A", capacity: 30, description: "Primer año sección A" },
  { id: "c2", name: "2B", grade: "2°", section: "B", capacity: 28, description: "Segundo año sección B" },
  { id: "c3", name: "3A", grade: "3°", section: "A", capacity: 32, description: "Tercer año sección A" },
];

function ClassroomsView({ classrooms, setClassrooms, students, users }) {
  const [showModal, setShowModal] = useState(false);
  const [editId, setEditId] = useState(null);
  const [form, setForm] = useState({ name: "", grade: "", section: "", capacity: "", description: "" });
  const [deleteConfirm, setDeleteConfirm] = useState(null);

  const teachers = users.filter(u => u.role === "teacher");

  function openNew() {
    setForm({ name: "", grade: "", section: "", capacity: "", description: "" });
    setEditId(null);
    setShowModal(true);
  }

  function openEdit(c) {
    setForm({ name: c.name, grade: c.grade, section: c.section, capacity: String(c.capacity), description: c.description });
    setEditId(c.id);
    setShowModal(true);
  }

  function save() {
    if (!form.name.trim()) return;
    const data = { ...form, capacity: parseInt(form.capacity) || 0 };
    if (editId) {
      setClassrooms(prev => prev.map(c => c.id === editId ? { ...c, ...data } : c));
      setEditId(null);
    } else {
      setClassrooms(prev => [...prev, { ...data, id: `c${Date.now()}` }]);
    }
    setShowModal(false);
  }

  function confirmDelete(id) { setDeleteConfirm(id); }

  function del() {
    setClassrooms(prev => prev.filter(c => c.id !== deleteConfirm));
    setDeleteConfirm(null);
  }

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24 }}>
        <h2 style={{ ...pageTitle, margin: 0 }}>Gestión de Aulas</h2>
        <button onClick={openNew} style={{
          padding: "10px 20px", background: COLORS.navy, color: "#fff",
          border: "none", borderRadius: 10, fontWeight: 700, fontSize: 13, cursor: "pointer"
        }}>+ Nueva Aula</button>
      </div>

      {/* Summary cards */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px,1fr))", gap: 14, marginBottom: 24 }}>
        {[
          { label: "Total aulas", val: classrooms.length, icon: "🏫", color: COLORS.navy },
          { label: "Capacidad total", val: classrooms.reduce((a, c) => a + (c.capacity || 0), 0), icon: "👥", color: COLORS.sky },
          { label: "Estudiantes", val: students.length, icon: "🎓", color: COLORS.emerald },
          { label: "Sin docente", val: classrooms.filter(c => !teachers.find(t => (t.classes||[]).includes(c.name))).length, icon: "⚠️", color: COLORS.amber },
        ].map(s => (
          <div key={s.label} style={{ ...card, padding: "18px 16px", textAlign: "center" }}>
            <div style={{ fontSize: 26 }}>{s.icon}</div>
            <div style={{ fontSize: 24, fontWeight: 800, color: s.color, marginTop: 4 }}>{s.val}</div>
            <div style={{ fontSize: 11, color: COLORS.gray400, marginTop: 2 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Classrooms grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px,1fr))", gap: 16 }}>
        {classrooms.map(c => {
          const classStudents = students.filter(s => s.course === c.name);
          const assignedTeacher = teachers.find(t => (t.classes || []).includes(c.name));
          const occupancy = c.capacity > 0 ? Math.round((classStudents.length / c.capacity) * 100) : 0;
          return (
            <div key={c.id} style={{
              background: COLORS.white, borderRadius: 16,
              border: `1px solid ${COLORS.gray100}`,
              boxShadow: "0 2px 12px rgba(0,0,0,.05)",
              overflow: "hidden"
            }}>
              {/* Header */}
              <div style={{
                background: `linear-gradient(135deg, ${COLORS.navy}, ${COLORS.navyLight})`,
                padding: "18px 20px", display: "flex", justifyContent: "space-between", alignItems: "flex-start"
              }}>
                <div>
                  <div style={{ fontSize: 28, fontWeight: 900, color: "#fff", letterSpacing: "-.02em" }}>
                    {c.name}
                  </div>
                  <div style={{ fontSize: 12, color: "rgba(255,255,255,.6)", marginTop: 2 }}>
                    {c.grade} grado · Sección {c.section}
                  </div>
                </div>
                <div style={{ display: "flex", gap: 6 }}>
                  <button onClick={() => openEdit(c)} style={iconBtn("rgba(255,255,255,.15)", "#fff")}>✏️</button>
                  <button onClick={() => confirmDelete(c.id)} style={iconBtn("rgba(244,63,94,.2)", "#FDA4AF")}>🗑️</button>
                </div>
              </div>

              {/* Body */}
              <div style={{ padding: "16px 20px" }}>
                {c.description && (
                  <p style={{ margin: "0 0 12px", fontSize: 13, color: COLORS.gray600 }}>{c.description}</p>
                )}

                {/* Occupancy bar */}
                <div style={{ marginBottom: 14 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 5 }}>
                    <span style={{ fontSize: 12, color: COLORS.gray400 }}>Ocupación</span>
                    <span style={{ fontSize: 12, fontWeight: 700, color: COLORS.gray600 }}>
                      {classStudents.length}/{c.capacity || "—"} alumnos
                    </span>
                  </div>
                  <div style={{ height: 6, background: COLORS.gray100, borderRadius: 99, overflow: "hidden" }}>
                    <div style={{
                      height: "100%", borderRadius: 99,
                      width: `${Math.min(occupancy, 100)}%`,
                      background: occupancy > 90 ? COLORS.rose : occupancy > 70 ? COLORS.amber : COLORS.emerald,
                      transition: "width .3s"
                    }} />
                  </div>
                </div>

                {/* Teacher */}
                <div style={{
                  display: "flex", alignItems: "center", gap: 8,
                  padding: "10px 12px", borderRadius: 8,
                  background: assignedTeacher ? COLORS.gray50 : "#FFF7ED",
                  border: `1px solid ${assignedTeacher ? COLORS.gray100 : COLORS.amber + "44"}`
                }}>
                  <span style={{ fontSize: 16 }}>{assignedTeacher ? "👩‍🏫" : "⚠️"}</span>
                  <span style={{ fontSize: 13, fontWeight: 600, color: assignedTeacher ? COLORS.gray700 : COLORS.amber }}>
                    {assignedTeacher ? assignedTeacher.name : "Sin docente asignado"}
                  </span>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {classrooms.length === 0 && (
        <div style={{ ...card, padding: 48, textAlign: "center" }}>
          <div style={{ fontSize: 48, marginBottom: 12 }}>🏫</div>
          <div style={{ fontWeight: 700, color: COLORS.gray600, marginBottom: 4 }}>No hay aulas creadas</div>
          <div style={{ fontSize: 13, color: COLORS.gray400 }}>Crea la primera aula con el botón de arriba</div>
        </div>
      )}

      {/* Create / Edit Modal */}
      {showModal && (
        <div style={modalOverlay}>
          <div style={{ ...modalBox, width: 440 }}>
            <h3 style={{ margin: "0 0 20px", color: COLORS.navy }}>{editId ? "Editar Aula" : "Nueva Aula"}</h3>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 14 }}>
              <div style={{ gridColumn: "1 / -1" }}>
                <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginBottom: 4 }}>
                  Nombre del aula <span style={{ color: COLORS.rose }}>*</span>
                </label>
                <input value={form.name} onChange={e => setForm(p => ({ ...p, name: e.target.value }))}
                  placeholder="Ej: 1A, 2B, 4C..." style={inputStyle} />
              </div>
              <div>
                <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginBottom: 4 }}>Grado</label>
                <input value={form.grade} onChange={e => setForm(p => ({ ...p, grade: e.target.value }))}
                  placeholder="Ej: 1°, 2°..." style={inputStyle} />
              </div>
              <div>
                <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginBottom: 4 }}>Sección</label>
                <input value={form.section} onChange={e => setForm(p => ({ ...p, section: e.target.value }))}
                  placeholder="Ej: A, B, C..." style={inputStyle} />
              </div>
              <div style={{ gridColumn: "1 / -1" }}>
                <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginBottom: 4 }}>Capacidad máxima</label>
                <input type="number" value={form.capacity} onChange={e => setForm(p => ({ ...p, capacity: e.target.value }))}
                  placeholder="Ej: 30" style={inputStyle} />
              </div>
              <div style={{ gridColumn: "1 / -1" }}>
                <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: COLORS.gray600, marginBottom: 4 }}>Descripción (opcional)</label>
                <input value={form.description} onChange={e => setForm(p => ({ ...p, description: e.target.value }))}
                  placeholder="Ej: Primer año sección A" style={inputStyle} />
              </div>
            </div>
            <p style={{ fontSize: 12, color: COLORS.gray400, margin: "0 0 16px" }}>
              💡 El nombre del aula debe coincidir exactamente con el curso de los estudiantes para vincularlos.
            </p>
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={save} style={{
                flex: 1, padding: "11px", background: COLORS.navy, color: "#fff",
                border: "none", borderRadius: 10, fontWeight: 700, cursor: "pointer"
              }}>{editId ? "Guardar cambios" : "Crear aula"}</button>
              <button onClick={() => setShowModal(false)} style={{
                padding: "11px 20px", background: COLORS.gray100, color: COLORS.gray600,
                border: "none", borderRadius: 10, fontWeight: 600, cursor: "pointer"
              }}>Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {/* Delete Confirm Modal */}
      {deleteConfirm && (
        <div style={modalOverlay}>
          <div style={{ ...modalBox, width: 360, textAlign: "center" }}>
            <div style={{ fontSize: 44, marginBottom: 12 }}>🗑️</div>
            <h3 style={{ margin: "0 0 8px", color: COLORS.navy }}>¿Eliminar aula?</h3>
            <p style={{ fontSize: 14, color: COLORS.gray600, margin: "0 0 24px" }}>
              Esta acción no elimina a los estudiantes ni al docente, solo el registro del aula.
            </p>
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={del} style={{
                flex: 1, padding: "11px", background: COLORS.rose, color: "#fff",
                border: "none", borderRadius: 10, fontWeight: 700, cursor: "pointer"
              }}>Sí, eliminar</button>
              <button onClick={() => setDeleteConfirm(null)} style={{
                flex: 1, padding: "11px", background: COLORS.gray100, color: COLORS.gray600,
                border: "none", borderRadius: 10, fontWeight: 600, cursor: "pointer"
              }}>Cancelar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── ADMIN DASHBOARD ──────────────────────────────────────────────────────────
function DashboardView({ users, students, attendance }) {
  const teachers = users.filter(u => u.role === "teacher");
  const courses = [...new Set(students.map(s => s.course))];
  const totalPresent = students.reduce((a, s) => a + getAttendanceStats(s.id, attendance).present, 0);
  const totalClasses = students.reduce((a, s) => a + getAttendanceStats(s.id, attendance).total, 0);
  const overallPct = totalClasses > 0 ? Math.round((totalPresent / totalClasses) * 100) : 0;

  return (
    <div>
      <h2 style={pageTitle}>Dashboard</h2>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(160px,1fr))", gap: 16, marginBottom: 28 }}>
        {[
          { label: "Docentes", val: teachers.length, icon: "👩‍🏫", color: COLORS.navy },
          { label: "Estudiantes", val: students.length, icon: "🎓", color: COLORS.sky },
          { label: "Cursos", val: courses.length, icon: "📚", color: COLORS.amber },
          { label: "Asistencia global", val: `${overallPct}%`, icon: "📊", color: COLORS.emerald },
        ].map(c => (
          <div key={c.label} style={{ ...card, padding: "22px 20px", textAlign: "center" }}>
            <div style={{ fontSize: 30 }}>{c.icon}</div>
            <div style={{ fontSize: 28, fontWeight: 800, color: c.color, marginTop: 4 }}>{c.val}</div>
            <div style={{ fontSize: 12, color: COLORS.gray400, marginTop: 2 }}>{c.label}</div>
          </div>
        ))}
      </div>

      <h3 style={{ color: COLORS.navy, fontWeight: 700 }}>Resumen por curso</h3>
      <div style={{ display: "grid", gap: 12 }}>
        {courses.map(c => {
          const cs = students.filter(s => s.course === c);
          const pct = cs.length
            ? Math.round(cs.reduce((a, s) => a + getAttendanceStats(s.id, attendance).pct, 0) / cs.length)
            : 0;
          const teacher = teachers.find(t => (t.classes || []).includes(c));
          return (
            <div key={c} style={{ ...card, padding: "16px 20px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div>
                <div style={{ fontWeight: 700, color: COLORS.gray800, fontSize: 16 }}>Curso {c}</div>
                <div style={{ fontSize: 13, color: COLORS.gray400 }}>
                  {cs.length} alumnos · {teacher ? teacher.name : "Sin docente asignado"}
                </div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{ fontWeight: 800, fontSize: 22, color: pct >= 75 ? COLORS.emerald : pct >= 50 ? COLORS.amber : COLORS.rose }}>
                  {pct}%
                </div>
                <div style={{ fontSize: 12, color: COLORS.gray400 }}>asistencia</div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─── STYLES ───────────────────────────────────────────────────────────────────
const pageTitle = { fontSize: 22, fontWeight: 800, color: COLORS.navy, margin: "0 0 24px" };
const card = {
  background: COLORS.white, borderRadius: 14,
  border: `1px solid ${COLORS.gray100}`,
  boxShadow: "0 2px 12px rgba(0,0,0,.05)", padding: 0, overflow: "hidden"
};
const th = { padding: "10px 14px", textAlign: "left", fontSize: 12, fontWeight: 700, color: COLORS.gray400, letterSpacing: ".05em", textTransform: "uppercase" };
const td = { padding: "12px 14px", fontSize: 14, color: COLORS.gray800 };
const selectStyle = {
  padding: "8px 12px", borderRadius: 8,
  border: `1.5px solid ${COLORS.gray200}`, fontSize: 14,
  color: COLORS.gray800, outline: "none", background: COLORS.white
};
const modalOverlay = {
  position: "fixed", inset: 0, background: "rgba(27,42,74,.5)",
  display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100
};
const modalBox = {
  background: COLORS.white, borderRadius: 16, padding: 28,
  width: 400, boxShadow: "0 24px 64px rgba(0,0,0,.2)"
};
const actionBtn = (color) => ({
  padding: "9px 16px", background: color + "22", color,
  border: `1px solid ${color}55`, borderRadius: 8,
  fontWeight: 600, cursor: "pointer", fontSize: 12
});
const iconBtn = (bg, color) => ({
  width: 34, height: 34, borderRadius: 8, border: "none",
  background: bg, color, cursor: "pointer", fontSize: 16,
  display: "inline-flex", alignItems: "center", justifyContent: "center"
});

// ─── PERSISTENCIA localStorage ────────────────────────────────────────────────
function loadData(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch { return fallback; }
}
function saveData(key, value) {
  try { localStorage.setItem(key, JSON.stringify(value)); } catch {}
}
function usePersisted(key, initial) {
  const [state, setState] = useState(() => loadData(key, initial));
  function setPersisted(val) {
    setState(prev => {
      const next = typeof val === "function" ? val(prev) : val;
      saveData(key, next);
      return next;
    });
  }
  return [state, setPersisted];
}

// ─── APP ROOT ─────────────────────────────────────────────────────────────────
export default function App() {
  const [users, setUsers] = usePersisted("edu_users", INITIAL_USERS);
  const [students, setStudents] = usePersisted("edu_students", INITIAL_STUDENTS);
  const [classrooms, setClassrooms] = usePersisted("edu_classrooms", INITIAL_CLASSROOMS);
  const [attendance, setAttendance] = usePersisted("edu_attendance", initAttendance(INITIAL_STUDENTS));
  const [currentUser, setCurrentUser] = useState(null);
  const [view, setView] = useState(null);
  const isMobile = useIsMobile();

  function handleLogin(user) {
    setCurrentUser(user);
    setView(user.role === "admin" ? "dashboard" : "attendance");
  }

  function handleLogout() { setCurrentUser(null); setView(null); }

  if (!currentUser) return <Login users={users} onLogin={handleLogin} />;

  const teacherNav = [
    { id: "attendance", icon: "✅", label: "Asistencia" },
    { id: "reports", icon: "📊", label: "Reportes" },
  ];
  const adminNav = [
    { id: "dashboard", icon: "🏠", label: "Inicio" },
    { id: "classrooms", icon: "🏫", label: "Aulas" },
    { id: "teachers", icon: "👩‍🏫", label: "Docentes" },
    { id: "students", icon: "🎓", label: "Alumnos" },
    { id: "reports", icon: "📊", label: "Reportes" },
  ];
  const nav = currentUser.role === "admin" ? adminNav : teacherNav;

  const viewMap = {
    dashboard: <DashboardView users={users} students={students} attendance={attendance} />,
    classrooms: <ClassroomsView classrooms={classrooms} setClassrooms={setClassrooms} students={students} users={users} />,
    attendance: <AttendanceView user={currentUser} students={students} attendance={attendance} setAttendance={setAttendance} />,
    reports: <ReportsView user={currentUser} students={students} attendance={attendance} />,
    teachers: <TeachersView users={users} setUsers={setUsers} students={students} classrooms={classrooms} />,
    students: <StudentsView students={students} setStudents={setStudents} />,
  };

  if (isMobile) {
    return (
      <div style={{ fontFamily: "'Inter', system-ui, sans-serif", background: COLORS.gray50, minHeight: "100vh" }}>
        <TopBar user={currentUser} currentView={view} nav={nav} onLogout={handleLogout} />
        <main style={{
          paddingTop: 64, paddingBottom: 70,
          paddingLeft: 14, paddingRight: 14,
          minHeight: "100vh"
        }}>
          {viewMap[view] || null}
        </main>
        <BottomNav nav={nav} view={view} setView={setView} />
      </div>
    );
  }

  return (
    <div style={{ display: "flex", minHeight: "100vh", fontFamily: "'Inter', system-ui, sans-serif", background: COLORS.gray50 }}>
      <Sidebar user={currentUser} view={view} setView={setView} onLogout={handleLogout} />
      <main style={{ flex: 1, padding: "32px 36px", overflowY: "auto" }}>
        {viewMap[view] || null}
      </main>
    </div>
  );
}
